 * Valid XML names must start with a letter or underscore, and contain only valid name characters.
 * @param name the name to validate
 * @return true if the name is valid
 */
private boolean isValidXmlName(String name) {
    if (name == null || name.isEmpty()) {
        return false;
    }
    // Must start with letter, underscore, or colon
    char firstChar = name.charAt(0);
    if (!(Character.isLetter(firstChar) || firstChar == '_' || firstChar == ':')) {
        return false;
    }
    // Remaining characters must be valid name characters
    for (int i = 1; i < name.length(); i++) {
        char c = name.charAt(i);
        if (!(Character.isLetterOrDigit(c) || c == '.' || c == '-' || c == '_' || c == ':')) {
            return false;
        }
    }
    return true;
}

